pragma solidity 0.4.24;

import "../../utils/LibBytes/LibBytes.sol";
import "./mixins/MSignatureValidator.sol";
import "./mixins/MTransactions.sol";
import "./interfaces/IWallet.sol";
import "./interfaces/IValidator.sol";


contract MixinSignatureValidator is
    MSignatureValidator,
    MTransactions
{
    using LibBytes for bytes;


    mapping (bytes32 => mapping (address => bool)) public preSigned;


    mapping (address => mapping (address => bool)) public allowedValidators;





    function preSign(
        bytes32 hash,
        address signerAddress,
        bytes signature
    )
        external
    {

        require(
            isValidSignature(
                hash,
                signerAddress,
                signature
            ),
            "INVALID_SIGNATURE"
        );
        preSigned[hash][signerAddress] = true;
    }




    function setSignatureValidatorApproval(
        address validatorAddress,
        bool approval
    )
        external
    {
        address signerAddress = getCurrentContextAddress();
        allowedValidators[signerAddress][validatorAddress] = approval;
        emit SignatureValidatorApproval(
            signerAddress,
            validatorAddress,
            approval
        );
    }






    function isValidSignature(
        bytes32 hash,
        address signerAddress,
        bytes memory signature
    )
        public
        view
        returns (bool isValid)
    {
        require(
            signature.length > 0,
            "LENGTH_GREATER_THAN_0_REQUIRED"
        );


        uint8 signatureTypeRaw = uint8(signature.popLastByte());
        require(
            signatureTypeRaw < uint8(SignatureType.NSignatureTypes),
            "SIGNATURE_UNSUPPORTED"
        );


        SignatureType signatureType = SignatureType(signatureTypeRaw);


        uint8 v;
        bytes32 r;
        bytes32 s;
        address recovered;






        if (signatureType == SignatureType.Illegal) {
            revert("SIGNATURE_ILLEGAL");





        } else if (signatureType == SignatureType.Invalid) {
            require(
                signature.length == 0,
                "LENGTH_0_REQUIRED"
            );
            isValid = false;
            return isValid;


        } else if (signatureType == SignatureType.EIP712) {
            require(
                signature.length == 65,
                "LENGTH_65_REQUIRED"
            );
            v = uint8(signature[0]);
            r = signature.readBytes32(1);
            s = signature.readBytes32(33);
            recovered = ecrecover(hash, v, r, s);
            isValid = signerAddress == recovered;
            return isValid;


        } else if (signatureType == SignatureType.EthSign) {
            require(
                signature.length == 65,
                "LENGTH_65_REQUIRED"
            );
            v = uint8(signature[0]);
            r = signature.readBytes32(1);
            s = signature.readBytes32(33);
            recovered = ecrecover(
                keccak256(abi.encodePacked(
                    "\x19Ethereum Signed Message:\n32",
                    hash
                )),
                v,
                r,
                s
            );
            isValid = signerAddress == recovered;
            return isValid;









        } else if (signatureType == SignatureType.Caller) {
            require(
                signature.length == 0,
                "LENGTH_0_REQUIRED"
            );
            isValid = signerAddress == msg.sender;
            return isValid;



        } else if (signatureType == SignatureType.Wallet) {
            isValid = IWallet(signerAddress).isValidSignature(hash, signature);
            return isValid;








        } else if (signatureType == SignatureType.Validator) {


            address validatorAddress = signature.popLast20Bytes();


            if (!allowedValidators[signerAddress][validatorAddress]) {
                return false;
            }
            isValid = IValidator(validatorAddress).isValidSignature(
                hash,
                signerAddress,
                signature
            );
            return isValid;


        } else if (signatureType == SignatureType.PreSigned) {
            isValid = preSigned[hash][signerAddress];
            return isValid;









        } else if (signatureType == SignatureType.Trezor) {
            require(
                signature.length == 65,
                "LENGTH_65_REQUIRED"
            );
            v = uint8(signature[0]);
            r = signature.readBytes32(1);
            s = signature.readBytes32(33);
            recovered = ecrecover(
                keccak256(abi.encodePacked(
                    "\x19Ethereum Signed Message:\n\x20",
                    hash
                )),
                v,
                r,
                s
            );
            isValid = signerAddress == recovered;
            return isValid;
        }






        revert("SIGNATURE_UNSUPPORTED");
    }
}

pragma solidity ^0.7.3;

import "@openzeppelin/contracts-upgradeable/cryptography/ECDSAUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/utils/ContextUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/introspection/ERC165Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/IERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/SafeERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC721/ERC721HolderUpgradeable.sol";

import "./interfaces/IRegistrar.sol";

contract StakingController is
  Initializable,
  ContextUpgradeable,
  ERC165Upgradeable,
  ERC721HolderUpgradeable
{
  using ECDSAUpgradeable for bytes32;
  using SafeERC20Upgradeable for IERC20Upgradeable;

  IERC20Upgradeable private infinity;
  IRegistrar private registrar;
  address private controller;

  mapping(bytes32 => bool) private approvedBids;

  event DomainBidPlaced(
    bytes32 indexed unsignedRequestHash,
    string indexed bidIPFSHash,
    bytes indexed signature
  );

  event DomainBidApproved(string indexed bidIdentifier);

  event DomainBidFulfilled(
    string indexed bidIdentifier,
    string name,
    address recoveredbidder,
    uint256 indexed id,
    uint256 indexed parentID
  );

  modifier authorizedOwner(uint256 domain) {
    require(registrar.domainExists(domain), "ZNS: Invalid Domain");
    require(
      registrar.ownerOf(domain) == _msgSender(),
      "ZNS: Not Authorized Owner"
    );
    _;
  }

  function initialize(IRegistrar _registrar, IERC20Upgradeable _infinity)
    public
    initializer
  {
    __ERC165_init();
    __Context_init();

    infinity = _infinity;
    registrar = _registrar;
    controller = address(this);
  }


  function placeDomainBid(
    uint256 parentId,
    bytes32 unsignedRequestHash,
    bytes memory signature,
    string memory bidIPFSHash
  ) external {
    require(registrar.domainExists(parentId), "ZNS: Invalid Domain");
    emit DomainBidPlaced(unsignedRequestHash, bidIPFSHash, signature);
  }



  function approveDomainBid(
    uint256 parentId,
    string memory bidIPFSHash,
    bytes memory signature
  ) external authorizedOwner(parentId) {
    bytes32 hashOfSig = keccak256(abi.encode(signature));
    approvedBids[hashOfSig] = true;
    emit DomainBidApproved(bidIPFSHash);
  }



  function fulfillDomainBid(
    uint256 parentId,
    uint256 bidAmount,
    uint256 royaltyAmount,
    string memory bidIPFSHash,
    string memory name,
    string memory metadata,
    bytes memory signature,
    bool lockOnCreation,
    address recipient
  ) external {
    bytes32 recoveredBidHash = createBid(
      parentId,
      bidAmount,
      bidIPFSHash,
      name
    );

    address recoveredBidder = recover(recoveredBidHash, signature);
    require(recipient == recoveredBidder, "ZNS: bid info doesnt match/exist");
    bytes32 hashOfSig = keccak256(abi.encode(signature));
    require(approvedBids[hashOfSig] == true, "ZNS: has been fullfilled");
    infinity.safeTransferFrom(recoveredBidder, controller, bidAmount);
    uint256 id = registrar.registerDomain(
      parentId,
      name,
      controller,
      recoveredBidder
    );
    registrar.setDomainMetadataUri(id, metadata);
    registrar.setDomainRoyaltyAmount(id, royaltyAmount);
    registrar.transferFrom(controller, recoveredBidder, id);
    if (lockOnCreation) {
      registrar.lockDomainMetadataForOwner(id);
    }
    approvedBids[hashOfSig] = false;
    emit DomainBidFulfilled(metadata, name, recoveredBidder, id, parentId);
  }


  function recover(bytes32 unsignedRequestHash, bytes memory signature)
    public
    pure
    returns (address)
  {
    return unsignedRequestHash.toEthSignedMessageHash().recover(signature);
  }


  function createBid(
    uint256 parentId,
    uint256 bidAmount,
    string memory bidIPFSHash,
    string memory name
  ) public pure returns (bytes32) {
    return keccak256(abi.encode(parentId, bidAmount, bidIPFSHash, name));
  }
}

pragma solidity 0.6.11;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../contracts/interfaces/IDepositContract.sol";

contract AbyssEth2Depositor is Pausable, Ownable {
    using SafeMath for uint256;


    IDepositContract public depositContract;


    uint256 public constant nodesMinAmount = 1;
    uint256 public constant nodesMaxAmount = 100;


    uint256 public constant collateral = 32 ether;


    constructor(address depositContractAddress) public {
        depositContract = IDepositContract(address(depositContractAddress));
    }


    receive() external payable {
        revert("AbyssEth2Depositor: do not send ETH directly here");
    }




    function deposit(
        bytes[] calldata pubkeys,
        bytes[] calldata withdrawal_credentials,
        bytes[] calldata signatures,
        bytes32[] calldata deposit_data_roots
    ) external payable whenNotPaused {

        uint256 nodesAmount = pubkeys.length;

        require(nodesAmount > 0 && nodesAmount <= 100, "AbyssEth2Depositor: you can deposit only 1 to 100 nodes per transaction");
        require(msg.value == SafeMath.mul(collateral, nodesAmount), "AbyssEth2Depositor: the amount of ETH does not match the amount of nodes");
        require(
            withdrawal_credentials.length == nodesAmount &&
            signatures.length == nodesAmount &&
            deposit_data_roots.length == nodesAmount,
            "AbyssEth2Depositor: amount of parameters do no match");

        for (uint256 i = 0; i < nodesAmount; ++i) {

            IDepositContract(address(depositContract)).deposit{value: collateral}(
                pubkeys[i],
                withdrawal_credentials[i],
                signatures[i],
                deposit_data_roots[i]
            );

        }

        emit DepositEvent(msg.sender, nodesAmount);
    }


    function pause() public onlyOwner {
      _pause();
    }


    function unpause() public onlyOwner {
      _unpause();
    }

    event DepositEvent(address from, uint256 nodesAmount);
}

pragma solidity ^0.6.0;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "../utils/AccessControl.sol";
import "./IDepositaryBalanceView.sol";

contract RealAssetDepositaryBalanceView is IDepositaryBalanceView, AccessControl {
    using SafeMath for uint256;


    struct Proof {
        string data;
        string signature;
    }


    struct Asset {
        string id;
        uint256 amount;
        uint256 price;
    }


    uint256 public maxSize;


    uint256 public override decimals = 6;


    Asset[] public portfolio;


    mapping(string => uint256) internal portfolioIndex;


    event AssetUpdated(string id, uint256 updatedAt, Proof proof);


    event AssetRemoved(string id);


    constructor(uint256 _decimals, uint256 _maxSize) public {
        decimals = _decimals;
        maxSize = _maxSize;
    }


    function size() public view returns (uint256) {
        return portfolio.length;
    }


    function assets() external view returns (Asset[] memory) {
        Asset[] memory result = new Asset[](size());

        for (uint256 i = 0; i < size(); i++) {
            result[i] = portfolio[i];
        }

        return result;
    }



    function put(
        string calldata id,
        uint256 amount,
        uint256 price,
        uint256 updatedAt,
        string calldata proofData,
        string calldata proofSignature
    ) external onlyAllowed {
        require(size() < maxSize, "RealAssetDepositaryBalanceView::put: too many assets");

        uint256 valueIndex = portfolioIndex[id];
        if (valueIndex != 0) {
            portfolio[valueIndex.sub(1)] = Asset(id, amount, price);
        } else {
            portfolio.push(Asset(id, amount, price));
            portfolioIndex[id] = size();
        }
        emit AssetUpdated(id, updatedAt, Proof(proofData, proofSignature));
    }


    function remove(string calldata id) external onlyAllowed {
        uint256 valueIndex = portfolioIndex[id];
        require(valueIndex != 0, "RealAssetDepositaryBalanceView::remove: asset already removed");

        uint256 toDeleteIndex = valueIndex.sub(1);
        uint256 lastIndex = size().sub(1);
        Asset memory lastValue = portfolio[lastIndex];
        portfolio[toDeleteIndex] = lastValue;
        portfolioIndex[lastValue.id] = toDeleteIndex.add(1);
        portfolio.pop();
        delete portfolioIndex[id];

        emit AssetRemoved(id);
    }

    function balance() external view override returns (uint256) {
        uint256 result;

        for (uint256 i = 0; i < size(); i++) {
            result = result.add(portfolio[i].amount.mul(portfolio[i].price));
        }

        return result;
    }
}

